import streamlit as st
import pandas as pd
import plotly.express as px
import plotly.graph_objects as go
import io, base64

st.set_page_config(page_title="Disponibilidad de Salas 2026-02", layout="wide", page_icon="🏫")

@st.cache_data
def load_data():
    def d(s): return pd.read_csv(io.StringIO(base64.b64decode(s).decode()))
    return (d(""),d(""),d(""),d(""),
            d(""),d(""),d(""),
            d(""),d(""),d("TU9EVUxPLENsYXNlcwoxLjAsNjk5CjIuMCwxMDc2CjMuMCwxMDY4CjQuMCw0OTYKNS4wLDY4MAo2LjAsNzE1CjcuMCwzNTcK"),
            d(""),d(""),d(""))

df_res,df_det,df_fac,df_doc,df_cd,df_cs,df_ef_fac,df_ef_ed,df_ef_det,df_cm,df_cfm,df_ct,df_rev = load_data()

MODULOS = {1:"Mód 1 · 08:15",2:"Mód 2 · 09:45",3:"Mód 3 · 11:15",4:"Mód 4 · 12:45",5:"Mód 5 · 14:15",6:"Mód 6 · 15:45",7:"Mód 7 · 17:15"}
MODULOS_FULL = {1:"Mód 1 · 08:15–09:35",2:"Mód 2 · 09:45–11:05",3:"Mód 3 · 11:15–12:35",4:"Mód 4 · 12:45–14:05",5:"Mód 5 · 14:15–15:35",6:"Mód 6 · 15:45–17:05",7:"Mód 7 · 17:15–18:35"}
ED_SHORT = {"GONZALO HERNANDEZ URIBE TORRE B":"G.H. Torre B","GONZALO HERNANDEZ URIBE TORRE C":"G.H. Torre C",
    "GONZALO HERNANDEZ URIBE TORRE D":"G.H. Torre D","VICENTE KOVACEVIC I":"V. Kovacevic I","VICENTE KOVACEVIC II":"V. Kovacevic II"}
FAC_SHORT = {"FACULTAD DE MEDICINA Y CIENCIAS DE LA SALUD":"Medicina","FACULTAD DE INGENIERÍA":"Ingeniería",
    "VICERRECTORÍA ACADÉMICA":"Vicerrectoría","FACULTAD DE CIENCIAS DE LA EDUCACIÓN":"Educación",
    "FACULTAD DE DERECHO Y HUMANIDADES":"Derecho","FACULTAD DE ECONOMÍA, GOBIERNO Y COMUNICACIONES":"Econ./Gob./Com.",
    "FACULTAD DE GOBIERNO":"Gobierno","FACULTAD DE ARQUITECTURA, URBANISMO Y PAISAJE":"Arquitectura","INSTITUTO DE CARRERAS TÉCNICAS":"ICIT"}
DIAS_ORDER = ["Lunes","Martes","Miércoles","Jueves","Viernes"]
RANGO_ORDER = ["≤20 pax","21-30 pax","31-40 pax","41-50 pax","51+ pax"]

df_res["Ed_corto"] = df_res["Edificio"].map(ED_SHORT)
df_det["Ed_corto"] = df_det["Edificio"].map(ED_SHORT)
df_fac["Fac_corto"] = df_fac["Facultad"].map(FAC_SHORT).fillna(df_fac["Facultad"])
df_cfm["Fac_corto"] = df_cfm["FACULTAD"].map(FAC_SHORT).fillna(df_cfm["FACULTAD"])
df_ct["Fac_corto"] = df_ct["FACULTAD"].map(FAC_SHORT).fillna(df_ct["FACULTAD"])
df_ef_fac["Fac_corto"] = df_ef_fac["FACULTAD"].map(FAC_SHORT).fillna(df_ef_fac["FACULTAD"])
df_res["Dia"] = pd.Categorical(df_res["Dia"], categories=DIAS_ORDER, ordered=True)
df_det["Dia"] = pd.Categorical(df_det["Dia"], categories=DIAS_ORDER, ordered=True)

ocup_ed_df = df_res.drop_duplicates("Edificio")[["Ed_corto","Pct_Global_Edificio","Bloques_Posibles_Ed","Bloques_Ocupados_Ed"]].copy()
global_total_ocp = ocup_ed_df["Bloques_Ocupados_Ed"].sum()
global_total_pos = ocup_ed_df["Bloques_Posibles_Ed"].sum()
PCT_GLOBAL = round(global_total_ocp/global_total_pos*100,1)

st.sidebar.title("🔎 Filtros globales")
edificios_opts = list(ED_SHORT.values())
sel_ed = st.sidebar.multiselect("Edificio", edificios_opts, default=edificios_opts)
sel_dias = st.sidebar.multiselect("Día", DIAS_ORDER, default=DIAS_ORDER)
sel_mods = st.sidebar.multiselect("Módulo", list(MODULOS.keys()), format_func=lambda x: MODULOS_FULL[x], default=list(MODULOS.keys()))

fr = df_res[df_res["Ed_corto"].isin(sel_ed)&df_res["Dia"].isin(sel_dias)&df_res["Modulo"].isin(sel_mods)].copy()
fd = df_det[df_det["Ed_corto"].isin(sel_ed)&df_det["Dia"].isin(sel_dias)&df_det["Modulo"].isin(sel_mods)].copy()

st.title("🏫 Disponibilidad de Salas · 2026-02 · Santiago")
st.caption("Salas de clases y laboratorios de computación · Diurno L–V · Módulos 1–7")

# ── KPIs GLOBALES ─────────────────────────────────────────────────────────────
st.subheader("📌 Ocupación global horario diurno")
k1,k2,k3,k4,k5 = st.columns(5)
k1.metric("Ocupación global",f"{PCT_GLOBAL}%",delta=f"{round(100-PCT_GLOBAL,1)}% disponible",delta_color="inverse")
k2.metric("Bloques posibles",f"{global_total_pos:,}")
k3.metric("Bloques ocupados",f"{global_total_ocp:,}")
k4.metric("Bloques libres",f"{global_total_pos-global_total_ocp:,}")
k5.metric("Disponibilidad global",f"{round(100-PCT_GLOBAL,1)}%")

col_g1,col_g2 = st.columns([1,2])
with col_g1:
    fig_g = go.Figure(go.Indicator(mode="gauge+number",value=PCT_GLOBAL,
        title={"text":"% Ocupación global","font":{"size":14}},
        gauge={"axis":{"range":[0,100]},"bar":{"color":"#3266ad"},
               "steps":[{"range":[0,50],"color":"#d5f5e3"},{"range":[50,75],"color":"#fef9e7"},
                        {"range":[75,90],"color":"#fdebd0"},{"range":[90,100],"color":"#fadbd8"}],
               "threshold":{"line":{"color":"red","width":3},"thickness":0.75,"value":90}}))
    fig_g.update_layout(height=260,margin=dict(t=40,b=10,l=10,r=10))
    st.plotly_chart(fig_g,use_container_width=True)
with col_g2:
    ocup_s = ocup_ed_df.sort_values("Pct_Global_Edificio",ascending=True)
    fig_e = px.bar(ocup_s,x="Pct_Global_Edificio",y="Ed_corto",orientation="h",
        color="Pct_Global_Edificio",color_continuous_scale="RdYlGn_r",range_color=[0,100],text="Pct_Global_Edificio",
        labels={"Pct_Global_Edificio":"% Ocupación","Ed_corto":"Edificio"})
    fig_e.update_traces(texttemplate="%{text}%",textposition="outside")
    fig_e.add_vline(x=90,line_dash="dash",line_color="red")
    fig_e.update_layout(height=240,coloraxis_showscale=False,xaxis_range=[0,110],margin=dict(t=10,b=10))
    st.plotly_chart(fig_e,use_container_width=True)

st.divider()
if not fr.empty:
    c1,c2,c3,c4,c5 = st.columns(5)
    c1.metric("Bloques analizados",len(fr))
    c2.metric("Ocupación prom.",f"{fr['Pct_Ocupacion'].mean():.1f}%")
    c3.metric("Salas libres prom.",f"{fr['Libres'].mean():.1f}")
    c4.metric("Bloques críticos ≥90%",int((fr['Pct_Ocupacion']>=90).sum()))
    c5.metric("Bloques holgados ≤30%",int((fr['Pct_Ocupacion']<=30).sum()))
st.divider()

tabs = st.tabs(["📊 Saturación","📅 Por día","🪑 Cupos","🎓 Facultades",
                "👨‍🏫 Carga docente","⚠️ Conflictos","📐 Eficiencia salas",
                "🕐 Concentración horaria","📋 Reservas","🔍 Detalle salas"])

# ── TAB 1: SATURACIÓN ─────────────────────────────────────────────────────────
with tabs[0]:
    st.subheader("% Ocupación promedio por módulo y edificio")
    if not fr.empty:
        p = fr.groupby(["Ed_corto","Modulo"])["Pct_Ocupacion"].mean().reset_index()
        p["ML"] = p["Modulo"].map(lambda x: MODULOS[x])
        fig = px.bar(p,x="ML",y="Pct_Ocupacion",color="Ed_corto",barmode="group",
            labels={"ML":"Módulo","Pct_Ocupacion":"% Ocupación","Ed_corto":"Edificio"},
            color_discrete_sequence=px.colors.qualitative.Set2)
        fig.add_hline(y=90,line_dash="dash",line_color="red",annotation_text="90% crítico")
        fig.add_hline(y=70,line_dash="dot",line_color="orange",annotation_text="70% alerta")
        fig.update_layout(yaxis_range=[0,105],height=400)
        st.plotly_chart(fig,use_container_width=True)
        hm = fr.groupby(["Ed_corto","Modulo"])["Pct_Ocupacion"].mean().unstack("Modulo")
        hm.columns = [MODULOS[c] for c in hm.columns]
        fig2 = px.imshow(hm,text_auto=".1f",color_continuous_scale="RdYlGn_r",zmin=0,zmax=100,aspect="auto",height=280)
        fig2.update_xaxes(tickangle=-30)
        st.plotly_chart(fig2,use_container_width=True)
        p2 = fr.groupby("Modulo")[["Libres","Ocupadas"]].mean().reset_index()
        p2["ML"] = p2["Modulo"].map(lambda x: MODULOS[x])
        fig3 = px.bar(p2.melt(id_vars="ML",value_vars=["Libres","Ocupadas"]),
            x="ML",y="value",color="variable",barmode="stack",
            color_discrete_map={"Libres":"#2ecc71","Ocupadas":"#e74c3c"},
            labels={"ML":"Módulo","value":"Salas","variable":""})
        fig3.update_layout(height=300)
        st.plotly_chart(fig3,use_container_width=True)

# ── TAB 2: POR DÍA ────────────────────────────────────────────────────────────
with tabs[1]:
    if not fr.empty:
        sel2 = st.selectbox("Edificio",sel_ed if sel_ed else edificios_opts,key="ed2")
        fr2 = fr[fr["Ed_corto"]==sel2]
        if not fr2.empty:
            p3 = fr2.groupby(["Dia","Modulo"])["Libres"].mean().reset_index()
            p3["ML"] = p3["Modulo"].map(lambda x: MODULOS[x])
            p3["Dia"] = pd.Categorical(p3["Dia"],categories=DIAS_ORDER,ordered=True)
            fig4 = px.bar(p3.sort_values("Dia"),x="Dia",y="Libres",color="ML",barmode="group",
                color_discrete_sequence=px.colors.qualitative.Pastel,
                labels={"Dia":"Día","Libres":"Salas libres","ML":"Módulo"})
            fig4.update_layout(height=380)
            st.plotly_chart(fig4,use_container_width=True)
            tbl = p3.pivot(index="Dia",columns="ML",values="Libres").round(1)
            st.dataframe(tbl,use_container_width=True)
            p4 = fr2.groupby(["Dia","Modulo"])["Pct_Ocupacion"].mean().reset_index()
            p4["ML"] = p4["Modulo"].map(lambda x: MODULOS[x])
            p4["Dia"] = pd.Categorical(p4["Dia"],categories=DIAS_ORDER,ordered=True)
            fig5 = px.line(p4.sort_values("Dia"),x="Dia",y="Pct_Ocupacion",color="ML",markers=True,
                labels={"Dia":"Día","Pct_Ocupacion":"% Ocupación","ML":"Módulo"})
            fig5.add_hline(y=90,line_dash="dash",line_color="red")
            fig5.update_layout(height=320,yaxis_range=[0,105])
            st.plotly_chart(fig5,use_container_width=True)

# ── TAB 3: CUPOS ──────────────────────────────────────────────────────────────
with tabs[2]:
    if not fd.empty:
        ca,cb = st.columns(2)
        with ca: sel3e = st.selectbox("Edificio",sel_ed if sel_ed else edificios_opts,key="ed3")
        with cb: sel3d = st.selectbox("Día",sel_dias if sel_dias else DIAS_ORDER,key="dia3")
        fd3 = fd[(fd["Ed_corto"]==sel3e)&(fd["Dia"]==sel3d)].copy()
        if not fd3.empty:
            def rng(c):
                if c<=20: return "≤20 pax"
                if c<=30: return "21-30 pax"
                if c<=40: return "31-40 pax"
                if c<=50: return "41-50 pax"
                return "51+ pax"
            fd3["Rango"] = pd.Categorical(fd3["Capacidad"].apply(rng),categories=RANGO_ORDER,ordered=True)
            cnt = fd3.groupby(["Modulo","Rango"],observed=True).size().reset_index(name="Cant")
            cnt["ML"] = cnt["Modulo"].map(lambda x: MODULOS[x])
            fig6 = px.bar(cnt,x="ML",y="Cant",color="Rango",barmode="stack",
                color_discrete_sequence=["#2ecc71","#3498db","#9b59b6","#f39c12","#e74c3c"],
                category_orders={"Rango":RANGO_ORDER},labels={"ML":"Módulo","Cant":"Salas libres"})
            fig6.update_layout(height=380)
            st.plotly_chart(fig6,use_container_width=True)
            c1,c2 = st.columns(2)
            with c1:
                tc = fd3.groupby(["Modulo","Tipo"]).size().reset_index(name="Cant")
                tc["ML"] = tc["Modulo"].map(lambda x: MODULOS[x])
                fig7 = px.bar(tc,x="ML",y="Cant",color="Tipo",barmode="group",
                    color_discrete_map={"SALA DE CLASES":"#3498db","LABORATORIO DE COMPUTACION":"#e67e22"})
                fig7.update_layout(height=300,title="SC vs Laboratorio")
                st.plotly_chart(fig7,use_container_width=True)
            with c2:
                cm = fd3.groupby("Modulo")["Capacidad"].sum().reset_index()
                cm["ML"] = cm["Modulo"].map(lambda x: MODULOS[x])
                fig8 = px.bar(cm,x="ML",y="Capacidad",color="Capacidad",color_continuous_scale="Blues")
                fig8.update_layout(height=300,title="Cupos totales disponibles")
                st.plotly_chart(fig8,use_container_width=True)

# ── TAB 4: FACULTADES ─────────────────────────────────────────────────────────
with tabs[3]:
    st.subheader("🎓 Uso de salas por facultad")
    f1,f2,f3 = st.columns(3)
    f1.metric("Total bloques usados",f"{df_fac['Bloques_sala'].sum():,}")
    f2.metric("Con exceso de cupo",int((df_fac['Secc_exceso_cupo']>0).sum()))
    f3.metric("Secciones totales",f"{df_fac['Secciones'].sum():,}")
    fig_f1 = px.bar(df_fac.sort_values("Bloques_sala",ascending=True),x="Bloques_sala",y="Fac_corto",orientation="h",
        color="Bloques_sala",color_continuous_scale="Blues",text="Bloques_sala",
        labels={"Bloques_sala":"Bloques usados","Fac_corto":"Facultad"})
    fig_f1.update_traces(textposition="outside")
    fig_f1.update_layout(height=360,coloraxis_showscale=False)
    st.plotly_chart(fig_f1,use_container_width=True)
    c1,c2 = st.columns(2)
    with c1:
        fig_f2 = px.pie(df_fac,values="Secciones",names="Fac_corto",color_discrete_sequence=px.colors.qualitative.Set3)
        fig_f2.update_layout(height=320,title="Secciones por facultad")
        st.plotly_chart(fig_f2,use_container_width=True)
    with c2:
        fig_f3 = px.scatter(df_fac,x="Cap_sala_prom",y="Cupo_prom",size="Secciones",color="Fac_corto",text="Fac_corto",
            labels={"Cap_sala_prom":"Cap. prom. sala","Cupo_prom":"Cupo prom. sección"},
            color_discrete_sequence=px.colors.qualitative.Set2)
        fig_f3.add_shape(type="line",x0=0,y0=0,x1=60,y1=60,line=dict(color="red",dash="dash"))
        fig_f3.update_traces(textposition="top center")
        fig_f3.update_layout(height=320,showlegend=False,title="Cupo vs capacidad sala")
        st.plotly_chart(fig_f3,use_container_width=True)
    df_ft = df_fac[["Facultad","Secciones","Bloques_sala","Salas_distintas","Cupo_prom","Cap_sala_prom","Secc_exceso_cupo"]].copy()
    df_ft.columns = ["Facultad","Secciones","Bloques sala","Salas distintas","Cupo prom","Cap. sala prom","Secc. exceso"]
    st.dataframe(df_ft.sort_values("Bloques sala",ascending=False),use_container_width=True,hide_index=True)

# ── TAB 5: CARGA DOCENTE ──────────────────────────────────────────────────────
with tabs[4]:
    st.subheader("👨‍🏫 Carga docente")
    d1,d2,d3,d4 = st.columns(4)
    d1.metric("Docentes con asignación",len(df_doc))
    d2.metric("Horas prom. semanales",f"{df_doc['Horas_sem'].mean():.1f}")
    d3.metric("Máx. horas semanales",f"{df_doc['Horas_sem'].max():.1f}")
    d4.metric("Docentes con conflictos",int((df_doc['Conflictos_horario']>0).sum()))

    col_d1,col_d2 = st.columns(2)
    with col_d1:
        st.subheader("Distribución de horas semanales")
        fig_d1 = px.histogram(df_doc,x="Horas_sem",nbins=30,color_discrete_sequence=["#3266ad"],
            labels={"Horas_sem":"Horas semanales","count":"N° docentes"})
        fig_d1.update_layout(height=300)
        st.plotly_chart(fig_d1,use_container_width=True)
    with col_d2:
        st.subheader("Horas por facultad (promedio)")
        hf = df_doc.groupby("Facultad")["Horas_sem"].mean().reset_index().sort_values("Horas_sem",ascending=True)
        hf["Fac_corto"] = hf["Facultad"].map(FAC_SHORT).fillna(hf["Facultad"])
        fig_d2 = px.bar(hf,x="Horas_sem",y="Fac_corto",orientation="h",
            color="Horas_sem",color_continuous_scale="Oranges",text="Horas_sem",
            labels={"Horas_sem":"Horas prom.","Fac_corto":"Facultad"})
        fig_d2.update_traces(texttemplate="%{text:.1f}",textposition="outside")
        fig_d2.update_layout(height=300,coloraxis_showscale=False)
        st.plotly_chart(fig_d2,use_container_width=True)

    st.subheader("Top 20 docentes con mayor carga")
    top_doc = df_doc.nlargest(20,"Horas_sem")[["Docente","Facultad","Nivel","Secciones","Horas_sem","Dias_activos","Conflictos_horario"]].copy()
    top_doc["Facultad"] = top_doc["Facultad"].map(FAC_SHORT).fillna(top_doc["Facultad"])
    top_doc.columns = ["Docente","Facultad","Nivel","Secciones","Horas sem.","Días activos","Conflictos"]
    st.dataframe(top_doc,use_container_width=True,hide_index=True)

    st.subheader("Buscar docente")
    busq_doc = st.text_input("Nombre del docente",key="busq_doc")
    if busq_doc:
        res_doc = df_doc[df_doc["Docente"].str.contains(busq_doc,case=False,na=False)]
        if not res_doc.empty:
            st.dataframe(res_doc[["Docente","Facultad","Nivel","Secciones","Horas_sem","Dias_activos","Conflictos_horario"]],
                use_container_width=True,hide_index=True)
        else:
            st.warning("No se encontró ningún docente con ese nombre.")

# ── TAB 6: CONFLICTOS ─────────────────────────────────────────────────────────
with tabs[5]:
    st.subheader("⚠️ Conflictos de horario")
    cv1,cv2 = st.columns(2)
    cv1.metric("Conflictos docente (mismo horario)",len(df_cd))
    cv2.metric("Conflictos de sala (doble asignación)",len(df_cs))

    st.subheader("Docentes con 2+ clases en el mismo horario")
    st.caption("Puede indicar clases sin docente asignado definitivo o un error de programación.")
    df_cd_show = df_cd[["docente","DESC_DIA","HORA_INI","n_clases","asignaturas"]].copy()
